if (boolean(process.env.AUTH_GOOGLE_ENABLED)) {
  router.get(
    '/google/consent',
    web.auth.catchError,
    passport.authenticate('google', {
      accessType: 'offline',
      prompt: 'consent', // See google strategy in passport helper
      scope: [
        'https://www.googleapis.com/auth/userinfo.email',
        'https://www.googleapis.com/auth/userinfo.profile'
      ]
    })
  );
}

serveIndex.json = function _json (req, res, files, next, dir, showUp, icons, path) {
  // stat all files
  stat(path, files, function (err, fileList) {
    if (err) return next(err)

    // sort file list
    fileList.sort(fileSort)

    // serialize
    var body = JSON.stringify(fileList.map(function (file) {
      return file.name
    }))

    send(res, 'application/json', body)
  })
};

serveIndex.plain = function _plain (req, res, files, next, dir, showUp, icons, path) {
  // stat all files
  stat(path, files, function (err, fileList) {
    if (err) return next(err)

    // sort file list
    fileList.sort(fileSort)

    // serialize
    var body = fileList.map(function (file) {
      return file.name
    }).join('\n') + '\n'

    send(res, 'text/plain', body)
  })
};

try {
	const incrementResult = await config.store.increment(key)
	totalHits = incrementResult.totalHits
	resetTime = incrementResult.resetTime
} catch (error) {
	if (config.passOnStoreError) {
		config.logger.error(
			error,
			'express-rate-limit: error from store, allowing request without rate-limiting.',
		)
		next()
		return
	}

	throw error
}

switch (encoding) {
  case 'deflate':
    debug('inflate body')
    return zlib.createInflate()
  case 'gzip':
    debug('gunzip body')
    return zlib.createGunzip()
  case 'br':
    debug('brotli decompress body')
    return zlib.createBrotliDecompress()
  default:
    throw createError(415, 'unsupported content encoding "' + encoding + '"', {
      encoding: encoding,
      type: 'encoding.unsupported'
    })
}
